static PyObject *Dtool_Str_EggGroup(PyObject *self) {
  EggGroup *local_this = nullptr;
  if (!Dtool_Call_ExtractThisPointer(self, Dtool_EggGroup, (void **)&local_this)) {
    return nullptr;
  }

  std::ostringstream os;
  local_this->write(os, 0);
  std::string ss = os.str();
  return Dtool_WrapValue(ss);
}

static int Dtool_Traverse_EggGroup(PyObject *self, visitproc visit, void *arg) {
  // If the only reference remaining is the one held by the Python wrapper,
  // report the circular reference to Python's GC, so that it can break it.
  EggGroup *local_this;
  DTOOL_Call_ExtractThisPointerForType(self, &Dtool_EggGroup, (void**)(&local_this));
  if (local_this == nullptr) {
    return 0;
  }
  if (local_this->get_ref_count() == (int)((Dtool_PyInstDef *)self)->_memory_rules) {
    Py_VISIT(self);
  }
  return 0;
}

static int Dtool_Clear_EggGroup(PyObject *self) {
  if (Py_TYPE(self) != &Dtool_EggGroup._PyType && DtoolInstance_TYPE(self) == &Dtool_EggGroup) {
    DtoolProxy_EggGroup *proxy = (DtoolProxy_EggGroup *)DtoolInstance_VOID_PTR(self);
    Py_CLEAR(proxy->DtoolProxy::_self);
  }
  return 0;
}

